var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기절했었나...... 분명 폭발음이 들렸는데......","JPN":"気絶してたのか……たしか、爆発音がして……","ENG":"Did I pass out? I thought heard an explosion.","TWN":"暈過去了嗎……明明清楚聽到了爆炸聲……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"반응로는...... 무사해 보이는군요.","JPN":"反応炉は……無事そうですね。","ENG":"The reactor... It looks unscathed.","TWN":"反應爐……看起來沒事啊。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다들 괜찮습니까?","JPN":"皆さん、大丈夫ですか？","ENG":"Is everyone okay?","TWN":"大家都沒事吧？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"네. 멀미가 좀 나긴 해도 팔다리는 멀쩡하게 붙어 있네요.","JPN":"はい、少しムカムカしますが、なんとか無事みたいです。","ENG":"Yes. I'm nauseated, but at least I still have all my limbs intact.","TWN":"是。雖然還有點暈，但至少沒有斷手斷腳。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_QM","text":{"KOREA":"어? 아닌가? 새끼발가락에서 감각이 없어진 것 같기도 하고?","JPN":"あれ？　そんなことないかな？　足の小指に感覚がないような……？","ENG":"Oh, wait. My pinky toe feels numb.","TWN":"嗯？沒有嗎？小拇指似乎也沒知覺了？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"......시영 씨, 의뢰인을 깔고 앉아도 된다는 조항은 계약서에 없었어요.","JPN":"……シノンさん、依頼人を座布団代わりにしても良いという内容は契約書にありません。","ENG":"Shiyoung, no clause in your contract says that you can sit on top of your client.","TWN":"……周時雨小姐，契約上沒有允許妳坐在委託人身上的條例。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_QM","text":{"KOREA":"엄살 부릴 시간에 그 무거운 엉덩이나 치우도록 하세요.","JPN":"適当な事を言ってないで、その重たいお尻をどかしてください。","ENG":"Please stop complaining and remove your buttocks this instance. They're heavy.","TWN":"可以麻煩妳從我身上下來嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"엇차, 실례.","JPN":"おっと、失礼。","ENG":"Oopsie, sorry.","TWN":"哎呀，失禮了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"누굽니까, 당신들은?!","JPN":"あなた方はどこから……！？","ENG":"Who are you?!","TWN":"你們是誰？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이곳 1급 군사기밀 시설로, 무단 침입자는 즉시 체포 대상입니다.","JPN":"ここは最上級の軍事機密施設で、無断で入った者は即時逮捕となります。","ENG":"This place is a classified military facility. Unauthorized intruders are to be arrested immediately.","TWN":"這裡是一級軍事機密設施，非法入侵者將立即被逮捕。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"즉시 무기를 내려 놓고 지시에 따르십시오.","JPN":"直ちに武器をおろして、指示に従ってください。","ENG":"Put down your weapons, and follow my instructions.","TWN":"請立刻放下武器並聽從指示。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"어─라?","JPN":"あれれ？","ENG":"Err?","TWN":"哦—呀？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양, 혹시나 해서 물어보는 건데 어릴 때 헤어진 쌍둥이 오빠가 계시나요?","JPN":"カリンさん、もしかして、子どもの頃生き別れになった双子のお兄さんがいるんですか？　","ENG":"Karin, just out of curiosity, do you have a twin brother whom you don't know about?","TWN":"卡琳小姐，以防萬一問一下，妳是不是有個幼時失散的雙胞胎哥哥啊？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 외동딸이에요. 의심되면 출생 기록이라도 열람해 보시던지요.","JPN":"私は一人っ子ですよ。信じられないなら出生記録でも確認してみては？","ENG":"I'm an only child. If you don't believe me, you can check my birth certificate.","TWN":"我是獨生女。不信的話，妳去查查出生記錄啊。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 우리 목적지에는 생명체가 있을 수 없어요.","JPN":"それに、私たちの目的地に生命体がいるわけないです。","ENG":"Besides, there shouldn't be any living things at our destination.","TWN":"還有，我們的目的地不可能有生命體。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만에 하나 제가 모르는 친족이 있더라도 여기서 만날 확률은 소수점 세 자리 이하입니다.","JPN":"万が一私の知らない親族がいるとしても、ここでバッタリ会うなんて小数点3ケタ以下の確率です。","ENG":"Even if there's a family member that I don't know about, my chance of meeting him here is lower than 0.001.","TWN":"即使有一個我不認識的親戚，我們在這裡相遇的可能性也不到0.001%。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};